CREATE OR REPLACE FUNCTION fpb_get_total_period ( as_keep_group CHAR ,as_conno CHAR ) RETURNS bigint AS $body$
DECLARE


li_period       sc_lon_m_contract.loan_installment_amount%TYPE;
ls_keep_group   sc_kep_m_ucf_keeping_item_type.keeping_type_group%type;

BEGIN
    ls_keep_group := trim(both as_keep_group);
    case trim(both upper( ls_keep_group ))
      when 'LON' then
        SELECT  sc_lon_m_contract.loan_installment_amount
        INTO STRICT    li_period
        FROM    sc_lon_m_contract
        WHERE   sc_lon_m_contract.loan_contract_no = as_conno;
        return li_period;
    else
        return 0;
      end case;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
